import android.util.Log
import timber.log.Timber

object Logger {
    fun logAuthenticationAttempt(username: String, success: Boolean) {
        val message = if (success) "Login successful" else "Login failed"
        Timber.d("AUTHENTICATION $message for user $username")
    }

    fun logDatabaseQuery(query: String, params: Map<String, Any?>) {
        Timber.v("DATABASE QUERY Executing query: $query with parameters: ${params.toString()}")
    }

    fun logApiRequest(method: String, url: String, headers: Map<String, String>, body: Any?) {
        val headerString = headers.map { "${it.key}: ${it.value}" }.joinToString("\n")
        Timber.v("API REQUEST $method $url\nHeaders:\n$headerString\nBody: $body")
    }

    fun logException(e: Throwable) {
        Timber.e(e, "EXCEPTION Occurred")
    }
}

class AppTree : Timber.DebugTree() {
    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        super.log(priority, tag, message, t)
        if (t != null) {
            Logger.logException(t)
        } else {
            when (priority) {
                Log.DEBUG -> Timber.d(message)
                Log.VERBOSE -> Timber.v(message)
                Log.INFO -> Timber.i(message)
                Log.WARN -> Timber.w(message)
                Log.ERROR -> Timber.e(message)
                else -> {}
            }
        }
    }
}

